#!/usr/bin/env node
// Rewrites android/capacitor.settings.gradle with a portable multi-path resolver.
// Run after every `npx cap sync android` to prevent pnpm-internal paths from
// breaking builds on other machines.

const fs = require('fs');
const path = require('path');

const dest = path.join(__dirname, '..', 'android', 'capacitor.settings.gradle');

const content = `\
// DO NOT EDIT THIS FILE! IT IS GENERATED EACH TIME "capacitor update" IS RUN

// Resolve a Capacitor plugin directory by trying multiple candidate paths.
// This makes the build portable across pnpm workspaces, npm installs, and
// downloaded Replit project ZIPs regardless of the host OS.
def resolveCapacitorDir(candidates) {
    for (rel in candidates) {
        def dir = new File(settingsDir, rel)
        if (dir.exists() && new File(dir, 'build.gradle').exists()) {
            return dir
        }
    }
    throw new GradleException(
        "Cannot find Capacitor plugin. Tried:\\n" + candidates.collect { "  \${new File(settingsDir, it).absolutePath}" }.join("\\n")
    )
}

include ':capacitor-android'
project(':capacitor-android').projectDir = resolveCapacitorDir([
    '../node_modules/@capacitor/android/capacitor',
    '../../../node_modules/.pnpm/@capacitor+android@8.4.0_@capacitor+core@8.4.0/node_modules/@capacitor/android/capacitor',
    '../../../node_modules/@capacitor/android/capacitor',
])

include ':capacitor-app'
project(':capacitor-app').projectDir = resolveCapacitorDir([
    '../node_modules/@capacitor/app/android',
    '../../../node_modules/.pnpm/@capacitor+app@8.1.0_@capacitor+core@8.4.0/node_modules/@capacitor/app/android',
    '../../../node_modules/@capacitor/app/android',
])

include ':capacitor-local-notifications'
project(':capacitor-local-notifications').projectDir = resolveCapacitorDir([
    '../node_modules/@capacitor/local-notifications/android',
    '../../../node_modules/.pnpm/@capacitor+local-notifications@8.2.0_@capacitor+core@8.4.0/node_modules/@capacitor/local-notifications/android',
    '../../../node_modules/@capacitor/local-notifications/android',
])
`;

fs.writeFileSync(dest, content, 'utf8');
console.log('✅ capacitor.settings.gradle rewritten with portable multi-path resolver');
